package rms_v1;

// OpportunityService defines the gRPC service for managing opportunities.
service OpportunityService {
  // CreateOpportunity creates a new opportunity.
  rpc CreateOpportunity(CreateOpportunityRequest) returns (Opportunity) {
    option (google.api.http) = {
      post: "/api/v1/opportunities"
      body: "opportunity"
    };
  }
  // GetOpportunity retrieves an opportunity by ID.
  rpc GetOpportunity(GetOpportunityRequest) returns (Opportunity) {
    option (google.api.http) = {
      get: "/api/v1/opportunities/{id}"
    };
  }
  // UpdateOpportunity updates an existing opportunity.
  rpc UpdateOpportunity(UpdateOpportunityRequest) returns (Opportunity) {
    option (google.api.http) = {
      patch: "/api/v1/opportunities/{opportunity.id}"
      body: "opportunity"
    };
  }
  // ListOpportunities lists all opportunities with optional filters.
  rpc ListOpportunities(ListOpportunitiesRequest) returns (ListOpportunitiesResponse) {
    option (google.api.http) = {
      get: "/api/v1/opportunities"
    };
  }
  // ScoreLead calculates a lead score for an opportunity.
  rpc ScoreLead(ScoreLeadRequest) returns (ScoreLeadResponse) {
    option (google.api.http) = {
      post: "/api/v1/opportunities/{opportunity_id}/score"
      body: "*"
    };
  }
  // ApproveOpportunity approves an opportunity.
  rpc ApproveOpportunity(ApproveOpportunityRequest) returns (Opportunity) {
    option (google.api.http) = {
      post: "/api/v1/opportunities/{id}/approve"
      body: "*"
    };
  }
  // ConvertOpportunity converts an opportunity to a project.
  rpc ConvertOpportunity(ConvertOpportunityRequest) returns (Project) {
    option (google.api.http) = {
      post: "/api/v1/opportunities/{id}/convert"
      body: "*"
    };
  }
}

// ProjectService defines the gRPC service for managing projects.
service ProjectService {
  // CreateProject creates a new project.
  rpc CreateProject(CreateProjectRequest) returns (Project) {
    option (google.api.http) = {
      post: "/api/v1/projects"
      body: "project"
    };
  }
  // GetProject retrieves a project by ID.
  rpc GetProject(GetProjectRequest) returns (Project) {
    option (google.api.http) = {
      get: "/api/v1/projects/{id}"
    };
  }
  // UpdateProject updates an existing project.
  rpc UpdateProject(UpdateProjectRequest) returns (Project) {
    option (google.api.http) = {
      patch: "/api/v1/projects/{project.id}"
      body: "project"
    };
  }
  // ListProjects lists all projects with optional filters.
  rpc ListProjects(ListProjectsRequest) returns (ListProjectsResponse) {
    option (google.api.http) = {
      get: "/api/v1/projects"
    };
  }
}

