syntax = "proto3";

package rms.v1;

import "google/api/annotations.proto";
import "google/protobuf/timestamp.proto";

option go_package = "github.com/sigma1/rms-service/pkg/api/rms/v1;rmsv1";

// Opportunity represents a potential rental business deal.
message Opportunity {
  string id = 1;
  string customer_id = 2;
  OpportunityStatus status = 3;
  google.protobuf.Timestamp event_date_start = 4;
  google.protobuf.Timestamp event_date_end = 5;
  string venue = 6;
  int64 total_estimate_cents = 7;
  int32 lead_score = 8;
  string notes = 9;
  google.protobuf.Timestamp created_at = 10;
  google.protobuf.Timestamp updated_at = 11;
}

enum OpportunityStatus {
  OPPORTUNITY_STATUS_UNSPECIFIED = 0;
  OPPORTUNITY_STATUS_NEW = 1;
  OPPORTUNITY_STATUS_QUALIFIED = 2;
  OPPORTUNITY_STATUS_PROPOSED = 3;
  OPPORTUNITY_STATUS_APPROVED = 4;
  OPPORTUNITY_STATUS_LOST = 5;
  OPPORTUNITY_STATUS_CONVERTED = 6;
}

// Project represents a confirmed rental project.
message Project {
  string id = 1;
  string opportunity_id = 2;
  string customer_id = 3;
  ProjectStatus status = 4;
  google.protobuf.Timestamp confirmed_at = 5;
  repeated google.protobuf.Timestamp event_dates = 6;
  string venue_address = 7;
  string crew_notes = 8;
  google.protobuf.Timestamp created_at = 9;
  google.protobuf.Timestamp updated_at = 10;
}

enum ProjectStatus {
