package rms_v1;

// InventoryService defines the gRPC service for managing inventory.
service InventoryService {
  // GetStockLevel retrieves the current stock level for a product.
  rpc GetStockLevel(GetStockLevelRequest) returns (GetStockLevelResponse) {
    option (google.api.http) = {
      get: "/api/v1/inventory/stock/{product_id}"
    };
  }
  // RecordTransaction records an inventory movement (e.g., check-out, check-in).
  rpc RecordTransaction(RecordTransactionRequest) returns (InventoryTransaction) {
    option (google.api.http) = {
      post: "/api/v1/inventory/transactions"
      body: "transaction"
    };
  }
  // ScanBarcode processes a barcode scan for inventory operations.
  rpc ScanBarcode(ScanBarcodeRequest) returns (ScanBarcodeResponse) {
    option (google.api.http) = {
      post: "/api/v1/inventory/scan"
      body: "*"
    };
  }
  // ListInventoryTransactions lists inventory transactions.
  rpc ListInventoryTransactions(ListInventoryTransactionsRequest) returns (ListInventoryTransactionsResponse) {
    option (google.api.http) = {
      get: "/api/v1/inventory/transactions"
    };
  }
}

// CrewService defines the gRPC service for managing crew members.
service CrewService {
  // ListCrew lists all crew members.
  rpc ListCrew(ListCrewRequest) returns (ListCrewResponse) {
    option (google.api.http) = {
      get: "/api/v1/crew"
    };
  }
  // AssignCrew assigns a crew member to a project for a specific period.
  rpc AssignCrew(AssignCrewRequest) returns (CrewAssignment) {
    option (google.api.http) = {
      post: "/api/v1/crew/assign"
      body: "assignment"
    };
  }
  // ScheduleCrew schedules a crew member, potentially integrating with external calendars.
  rpc ScheduleCrew(ScheduleCrewRequest) returns (ScheduleCrewResponse) {
    option (google.api.http) = {
      post: "/api/v1/crew/{crew_member_id}/schedule"
      body: "*"
    };
  }
}

// DeliveryService defines the gRPC service for managing deliveries.
service DeliveryService {
  // ScheduleDelivery creates a new delivery schedule.
  rpc ScheduleDelivery(ScheduleDeliveryRequest) returns (Delivery) {
    option (google.api.http) = {
      post: "/api/v1/deliveries/schedule"
      body: "delivery"
    };
  }
  // UpdateDeliveryStatus updates the status of a delivery.
  rpc UpdateDeliveryStatus(UpdateDeliveryStatusRequest) returns (Delivery) {
    option (google.api.http) = {
      patch: "/api/v1/deliveries/{delivery.id}/status"
      body: "*"
    };
  }
  // OptimizeRoute suggests an optimized route for multiple deliveries.
  rpc OptimizeRoute(OptimizeRouteRequest) returns (OptimizeRouteResponse) {
    option (google.api.http) = {
      post: "/api/v1/deliveries/optimize-route"
      body: "*"
    };
  }
  // ListDeliveries lists all deliveries.
  rpc ListDeliveries(ListDeliveriesRequest) returns (ListDeliveriesResponse) {
    option (google.api.http) = {
      get: "/api/v1/deliveries"
    };
  }
}

