#[tokio::test]
async fn test_create_invoice() {
    let pool = setup_test_db().await;
    let app = app_router(pool);

    let now = Utc::now();
    let new_invoice = CreateInvoiceRequest {
        project_id: Uuid::new_v4(),
        org_id: Uuid::new_v4(),
        invoice_number: "INV-001".to_string(),
        issued_at: now,
        due_at: now + Duration::days(30),
        currency: "USD".to_string(),
        subtotal_cents: 10000,
        tax_cents: 1000,
        total_cents: 11000,
    };

    let response = app
        .oneshot(
            Request::builder()
                .method("POST")
                .uri("/api/v1/invoices")
                .header("Content-Type", "application/json")
                .body(Body::from(serde_json::to_string(&new_invoice).unwrap()))
                .unwrap(),
        )
        .await
        .unwrap();

    assert_eq!(response.status(), StatusCode::CREATED);
    let body = hyper::body::to_bytes(response.into_body()).await.unwrap();
    let invoice: Invoice = serde_json::from_slice(&body).unwrap();
    assert_eq!(invoice.invoice_number, "INV-001");
    assert_eq!(invoice.status, "draft");
}

